solution_code:
#include <iostream>

constexpr int fib(int n) {
    if (n <= 0) return 0;
    if (n == 1) return 1;
    int a = 0, b = 1;
    for (int i = 2; i <= n; ++i) {
        int c = a + b;
        a = b;
        b = c;
    }
    return b;
}

int main() {
    constexpr int ct = fib(10);
    std::cout << "Compile-time fib(10): " << ct << "\n";

    int n;
    std::cin >> n;
    std::cout << "Runtime fib(" << n << "): " << fib(n) << "\n";
    return 0;
}

